-- 四川辰一思翰劳务有限公司身份信息记录表：人员库初始化数据
-- 来源：C:/Users/Administrator/Desktop/四川辰一思翰劳务有限公司-身份信息记录表.xlsx
-- 规则：按身份证号去重，保留非空字段更多的一条；非空数量相同则保留开户行名称更完整的一条。
-- 说明：created_by=1 表示导入到默认管理员名下；account_name 使用姓名作为户名。

USE lingdong_payroll;

ON DUPLICATE KEY UPDATE
    name = VALUES(name),
    phone = VALUES(phone),
    bank_account = VALUES(bank_account),
    account_name = VALUES(account_name),
    bank_name = VALUES(bank_name),
    bank_type = VALUES(bank_type),
    bank_category = VALUES(bank_category),
    cnaps_no = VALUES(cnaps_no),
    deleted = 0,
    updated_at = CURRENT_TIMESTAMP;

-- 如果重复执行，按 created_by + id_card_no 更新为本文件中的信息。
-- 需要依赖 payee_person 表上的唯一索引 uk_payee_created_id_card(created_by, id_card_no)。

